<?php require_once __DIR__.'/includes/bootstrap.php'; require_once __DIR__.'/models/User.php';
if(($_GET['state']??'')!==($_SESSION['google_oauth_state']??'')){$_SESSION['error']='Phiên Google không hợp lệ.';redirect('login.php');}
unset($_SESSION['google_oauth_state']);$code=$_GET['code']??'';if(!$code){$_SESSION['error']='Không nhận được code Google.';redirect('login.php');}
function gpost($url,$data){$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>true,CURLOPT_POST=>true,CURLOPT_POSTFIELDS=>http_build_query($data),CURLOPT_HTTPHEADER=>['Content-Type: application/x-www-form-urlencoded']]);$r=curl_exec($ch);if($r===false)throw new RuntimeException(curl_error($ch));curl_close($ch);return json_decode($r,true);}
function gget($url,$token){$ch=curl_init($url);curl_setopt_array($ch,[CURLOPT_RETURNTRANSFER=>true,CURLOPT_HTTPHEADER=>['Authorization: Bearer '.$token]]);$r=curl_exec($ch);if($r===false)throw new RuntimeException(curl_error($ch));curl_close($ch);return json_decode($r,true);}
try{$t=gpost('https://oauth2.googleapis.com/token',['code'=>$code,'client_id'=>GOOGLE_CLIENT_ID,'client_secret'=>GOOGLE_CLIENT_SECRET,'redirect_uri'=>GOOGLE_REDIRECT_URI,'grant_type'=>'authorization_code']);$gu=gget('https://www.googleapis.com/oauth2/v2/userinfo',$t['access_token']);$u=(new User(db_connect()))->createOrUpdateFromGoogle($gu);create_login_session($u);redirect('shop.php');}catch(Throwable $e){$_SESSION['error']='Google login lỗi: '.$e->getMessage();redirect('login.php');}
